const EXTRA_DATA = [{"id": 1001, "set": 31, "opdracht_in_set": 1, "title": "Kleding bij sollicitatie", "situatie": "Uw vriend heeft morgen een sollicitatiegesprek.\nHij wil een oude spijkerbroek en een t-shirt aandoen.\nU vindt dat geen goed idee.\nOvertuig uw vriend om iets anders aan te trekken.\nGeef een reden.\nU hoort eerst uw vriend.", "vraag": "IK TREK MORGEN GEWOON MIJN SPIJKERBROEK AAN NAAR HET SOLLICITATIEGESPREK. WAT VIND JIJ?", "antwoord": "Dat is geen goed idee. Met nette kleding maak je een betere eerste indruk.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2022 · Opgave 7 (yeniden kuruldu)"}, {"id": 1002, "set": 31, "opdracht_in_set": 2, "title": "Halve dagen werken", "situatie": "U werkt in een winkel.\nU gaat halve dagen werken.\nUw baas vraagt of u liever 's ochtends of 's middags werkt.\nVertel uw baas wanneer u het liefst werkt.\nVertel ook waarom.\nU hoort eerst uw baas.", "vraag": "WIL JE LIEVER 'S OCHTENDS OF 'S MIDDAGS WERKEN?", "antwoord": "Ik werk liever 's ochtends. Dan kan ik 's middags mijn kinderen van school halen.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 3 (yeniden kuruldu)"}, {"id": 1003, "set": 31, "opdracht_in_set": 3, "title": "Belegde broodjes", "situatie": "U werkt in een broodjeszaak.\nKlanten kunnen belegde broodjes alleen bij de andere balie bestellen.\nEen klant staat bij uw balie en wil een belegd broodje.\nLeg de klant uit wat hij moet doen.\nU hoort eerst de klant.", "vraag": "MAG IK EEN BROODJE KAAS BESTELLEN?", "antwoord": "Dat kan bij deze balie helaas niet, meneer. U kunt een belegd broodje bij de andere balie bestellen.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 4 (yeniden kuruldu)"}, {"id": 1004, "set": 31, "opdracht_in_set": 4, "title": "Opleiding volgen", "situatie": "U wilt een opleiding volgen.\nDe opleiding kan overdag en 's avonds.\nUw vriendin vraagt of u de avondopleiding gaat doen.\nVertel of u de avondopleiding wel of niet gaat volgen.\nVertel ook waarom.", "vraag": "GA JIJ DE AVONDOPLEIDING DOEN?", "antwoord": "Nee, ik kies de opleiding overdag. 's Avonds moet ik voor mijn kinderen zorgen.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 5 (yeniden kuruldu)"}, {"id": 1005, "set": 31, "opdracht_in_set": 5, "title": "Voor de kat zorgen", "situatie": "U gaat een week op vakantie.\nUw buurvrouw zorgt die week voor uw kat.\nVertel uw buurvrouw wat ze moet doen.\nU hoort eerst uw buurvrouw.", "vraag": "WAT MOET IK PRECIES DOEN?", "antwoord": "U moet de kat elke dag eten en water geven.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 6 (yeniden kuruldu)"}, {"id": 1006, "set": 31, "opdracht_in_set": 6, "title": "Verdrietig", "situatie": "U werkt in een verzorgingstehuis.\nMevrouw Verbeek is verdrietig, want haar zus is ziek.\nZeg iets om mevrouw Verbeek te troosten.", "vraag": "", "antwoord": "Wat vervelend voor u, mevrouw Verbeek. Ik hoop dat uw zus snel beter wordt.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 8 (yeniden kuruldu)"}, {"id": 1007, "set": 31, "opdracht_in_set": 7, "title": "Pakket voor de buurman", "situatie": "U bent thuis.\nDe postbezorger heeft een pakket voor uw buurman.\nUw buurman is niet thuis.\nDe postbezorger vraagt of u het pakket wilt aannemen.\nWat zegt u tegen de postbezorger?", "vraag": "", "antwoord": "Ja, dat is goed. Ik geef het pakket vanavond aan mijn buurman.", "pages": [], "image": null, "tag": "YENİ · resmi sınav formatında"}, {"id": 1008, "set": 31, "opdracht_in_set": 8, "title": "Te laat bij de tandarts", "situatie": "U hebt om tien uur een afspraak bij de tandarts.\nU staat in de file.\nU komt te laat.\nBel de tandarts en leg uit waarom u later komt.", "vraag": "", "antwoord": "Goedemorgen, ik heb om tien uur een afspraak. Ik sta in de file. Ik ben ongeveer een kwartier later.", "pages": [], "image": null, "tag": "YENİ · resmi sınav formatında"}, {"id": 1009, "set": 31, "opdracht_in_set": 9, "title": "Leren voor toets", "situatie": "U volgt een opleiding.\nEen medestudente heeft een slecht cijfer voor een toets gehaald.\nZe vraagt u om advies.\nVertel haar wat ze kan doen om beter voor een toets te leren.\nGeef ten minste twee adviezen.\nU hoort eerst uw medestudente.", "vraag": "IK HEB WEER EEN SLECHT CIJFER GEHAALD. HOE LEER JIJ VOOR EEN TOETS?", "antwoord": "Je kunt elke dag een uur studeren. En je moet je telefoon uitzetten. Dan heb je geen afleiding.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2022 · Opgave 12 (yeniden kuruldu)"}, {"id": 1010, "set": 31, "opdracht_in_set": 10, "title": "Lang weekend weg", "situatie": "U gaat een lang weekend weg met een vriend.\nU kunt naar Antwerpen of naar Parijs gaan.\nVertel uw vriend welke stad u kiest.\nGeef ten minste twee redenen.\nU hoort eerst uw vriend.", "vraag": "WAAR WIL JIJ NAARTOE, ANTWERPEN OF PARIJS?", "antwoord": "Ik kies Antwerpen. Antwerpen is dichtbij, dus de reis kost weinig tijd. En een hotel is daar goedkoper dan in Parijs.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 10 (yeniden kuruldu)"}, {"id": 1011, "set": 31, "opdracht_in_set": 11, "title": "Kopiëren", "situatie": "U werkt op een kantoor.\nEen nieuwe collega weet niet hoe de kopieermachine werkt.\nLeg uit hoe ze moet kopiëren.\nNoem drie stappen.\nU hoort eerst uw collega.", "vraag": "HOE WERKT DE KOPIEERMACHINE?", "antwoord": "Eerst legt u het papier op de machine. Dan kiest u het aantal kopieën. Daarna drukt u op de groene knop.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 11 (yeniden kuruldu)"}, {"id": 1012, "set": 31, "opdracht_in_set": 12, "title": "Bezoeker", "situatie": "U werkt bij de receptie van een groot bedrijf.\nEr komt een bezoeker voor een afspraak.\nVertel de bezoeker wat hij moet doen.\nNoem drie dingen.\nU hoort eerst de bezoeker.", "vraag": "GOEDEMORGEN, IK HEB EEN AFSPRAAK MET MEVROUW DE VRIES. WAT MOET IK DOEN?", "antwoord": "U moet zich eerst melden bij de receptie. Dan krijgt u een bezoekerspas. Daarna kunt u in de wachtruimte wachten.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 12 (yeniden kuruldu)"}, {"id": 1013, "set": 31, "opdracht_in_set": 13, "title": "Nieuwe studieruimte", "situatie": "Uw school heeft een nieuwe studieruimte.\nUw vriend wil weten hoe de ruimte eruitziet.\nBeschrijf de nieuwe studieruimte.\nNoem ten minste twee dingen.", "vraag": "HOE ZIET DE NIEUWE STUDIERUIMTE ERUIT?", "antwoord": "De ruimte is groot en licht. Er staan nieuwe tafels en computers. En het is er lekker rustig.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 13 (yeniden kuruldu)"}, {"id": 1014, "set": 31, "opdracht_in_set": 14, "title": "Voetbal of hardlopen", "situatie": "Uw vriend wil meer sporten.\nHij twijfelt tussen voetbal en hardlopen.\nHij vraagt u om advies.\nGeef uw vriend advies.\nGeef ten minste twee argumenten.", "vraag": "WAT ZAL IK KIEZEN: VOETBAL OF HARDLOPEN?", "antwoord": "Ik raad je hardlopen aan. Je kunt hardlopen wanneer je wilt. En het kost geen geld.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 14 (yeniden kuruldu)"}, {"id": 1015, "set": 31, "opdracht_in_set": 15, "title": "Meesters op school", "situatie": "Op de basisschool van uw kind werken bijna geen meesters, alleen juffen.\nU praat hierover met een andere ouder.\nVertel wat u ervan vindt dat er weinig meesters zijn.\nGeef ten minste twee argumenten.\nU hoort eerst de andere ouder.", "vraag": "ER ZIJN BIJNA GEEN MEESTERS OP SCHOOL. WAT VIND JIJ DAARVAN?", "antwoord": "Ik vind dat jammer. Kinderen leren van mannen en vrouwen verschillende dingen. En voor jongens is een meester soms een goed voorbeeld.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2023 · Opgave 16 (yeniden kuruldu)"}, {"id": 1016, "set": 31, "opdracht_in_set": 16, "title": "Begeleid wonen", "situatie": "U werkt in een huis voor begeleid wonen.\nEen kennis vraagt wat u daar precies doet.\nVertel over uw werkzaamheden.\nNoem ten minste twee taken.\nU hoort eerst uw kennis.", "vraag": "WAT DOE JE DAAR PRECIES?", "antwoord": "Ik help de bewoners met koken. Ik ga met ze mee naar de dokter. En ik help ze met hun geld.", "pages": [], "image": null, "tag": "ECHT EXAMEN 2024 · Opgave 10 (yeniden kuruldu)"}, {"id": 1017, "set": 31, "opdracht_in_set": 17, "title": "Telefoon of laptop", "situatie": "U krijgt geld van uw familie voor uw verjaardag.\nU kunt een nieuwe telefoon of een nieuwe laptop kopen.\nUw broer vraagt wat u kiest.\nVertel wat u kiest.\nGeef ten minste twee redenen.", "vraag": "WAT GA JE KOPEN, EEN TELEFOON OF EEN LAPTOP?", "antwoord": "Ik koop een laptop. Mijn telefoon werkt nog goed. En ik heb een laptop nodig voor mijn opleiding.", "pages": [], "image": null, "tag": "YENİ · resmi sınav formatında"}, {"id": 1018, "set": 31, "opdracht_in_set": 18, "title": "Fietsen naar het werk", "situatie": "Uw collega wil gezonder leven.\nZe vraagt of ze met de fiets naar het werk moet komen.\nGeef uw collega advies.\nGeef ten minste twee argumenten.", "vraag": "ZAL IK MET DE FIETS NAAR HET WERK KOMEN?", "antwoord": "Ja, dat is een goed idee! Fietsen is gezond, want je beweegt elke dag. En je staat nooit meer in de file.", "pages": [], "image": null, "tag": "YENİ · resmi sınav formatında"}];
